      "content": "const router = require('express').Router();
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  const comments = await commentsService.getAllComments(req.params.projectId, req.params.taskId);
  if (!comments) return sendError(res, 404, 'NOT_FOUND', 'Comments not found');
  res.json({ comments });
});

router.post('/', async (req, res) => {
  const message = String(req.body?.message || '').trim();
  if (!message) return sendError(res, 400, 'BAD_REQUEST', 'Message is required');
  const comment = await commentsService.addComment(req.params.projectId, req.params.taskId, message);
  if (!comment) return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to add comment');
  res.status(201).json({ comment });
});

module.exports = router;
